+package com.google.template.soy.jbcsrc;
+
+import com.google.template.soy.data.SoyValueHelper;
+import com.google.template.soy.data.internal.EasyDictImpl;
+import com.google.template.soy.data.restricted.IntegerData;
+import com.google.template.soy.jbcsrc.api.AdvisingStringBuilder;
+import com.google.template.soy.jbcsrc.api.CompiledTemplate;
+import com.google.template.soy.jbcsrc.api.RenderResult;
+
+import junit.framework.TestCase;
+
+public final class BytecodeCompilerParamTest extends TestCase {
+
+  public void testHeaderParamReferenceRenders() throws Exception {
+    CompiledTemplate.Factory factory = TemplateTester.compileTemplateBody(
+        "{@param foo : int }",
+        "{$foo + 1}");
+
+    assertRenders(factory, 1, "2");
+    assertRenders(factory, 3, "4");
+  }
+
+  private static void assertRenders(CompiledTemplate.Factory factory, int foo, String expected)
+      throws Exception {
+    EasyDictImpl params = new EasyDictImpl(SoyValueHelper.UNCUSTOMIZED_INSTANCE);
+    params.setField("foo", IntegerData.forValue(foo));
+
+    CompiledTemplate template = factory.create(params, SoyValueHelper.EMPTY_DICT);
+    AdvisingStringBuilder output = new AdvisingStringBuilder();
+    RenderResult result = template.render(output, TemplateTester.EMPTY_CONTEXT);
+
+    assertEquals(RenderResult.Type.DONE, result.type());
+    assertEquals(expected, output.toString());
+  }
+}
